const raw = $json.body ?? $json;
let data = raw;

if (typeof data === 'string') {
  try { data = JSON.parse(data); } catch { data = {}; }
}
if (typeof data !== 'object' || data === null || Array.isArray(data)) {
  data = {};
}

const pick = (obj, keys, fallback = '') => {
  for (const key of keys) {
    const val = obj[key];
    if (val !== undefined && val !== null && String(val).trim() !== '') {
      return typeof val === 'string' ? val.trim() : String(val);
    }
  }
  return fallback;
};

const dateBR = new Date().toLocaleDateString('pt-BR', {
  timeZone: 'America/Sao_Paulo',
});

// Campos enviados pela LP: nome, email, whatsapp, whatsapp_confirmacao, nivel_ml, regime_tributario
const nome            = pick(data, ['nome', 'Nome completo', 'name'], '');
const email           = pick(data, ['email', 'Qual seu e-mail?'], '');
const whatsapp        = pick(data, ['whatsapp', 'Qual o seu WhatsApp?'], '');
const whatsappConfirm = pick(data, ['whatsapp_confirmacao', 'Confirme seu WhatsApp'], '');
const medalha         = pick(data, ['nivel_ml', 'Qual é a sua medalha no Mercado Livre?'], '');
const regime          = pick(data, ['regime_tributario', 'Qual é o seu regime tributário atual?'], '');

const channel      = pick(data, ['channel', 'canal'], 'direto');
const utm_source   = pick(data, ['utm_source', 'source'], 'direto');
const utm_medium   = pick(data, ['utm_medium', 'medium'], 'none');
const utm_campaign = pick(data, ['utm_campaign', 'campaign'], 'none');
const utm_content  = pick(data, ['utm_content', 'content'], 'none');
const timestamp    = pick(data, ['timestamp'], new Date().toISOString());

return [
  {
    json: {
      'Entrada leads': dateBR,
      'Funil': 'Tributario',

      'Nome completo ': nome,
      'Qual seu e-mail?': email,
      'Qual o seu WhatsApp?': whatsapp,
      'Confirme seu WhatsApp': whatsappConfirm,
      'Qual é a sua medalha no Mercado Livre?': medalha,
      'Qual é o seu regime tributário atual?': regime,

      'channel': channel,
      'utm_source': utm_source,
      'utm_medium': utm_medium,
      'utm_campaign': utm_campaign,
      'utm_content': utm_content,
      'timestamp': timestamp
    }
  }
];
